<script setup lang="ts">
import { onMounted, onUnmounted, ref } from 'vue';

interface Section {
  id: string;
  label: string;
  icon?: string;
}

const props = defineProps<{
  sections: Section[];
  containerSelector?: string;
}>();

const activeId = ref<string>(props.sections[0]?.id ?? '');
const observer: { current: IntersectionObserver | null } = { current: null };

function scrollTo(id: string) {
  const el = document.getElementById(id);
  if (el) {
    el.scrollIntoView({ behavior: 'smooth', block: 'start' });
    activeId.value = id;
  }
}

onMounted(() => {
  const root = props.containerSelector ? document.querySelector(props.containerSelector) : null;
  const targets = props.sections
    .map(s => document.getElementById(s.id))
    .filter((el): el is HTMLElement => el !== null);

  if (!targets.length) return;

  observer.current = new IntersectionObserver(
    entries => {
      const visible = entries
        .filter(e => e.isIntersecting)
        .sort((a, b) => b.intersectionRatio - a.intersectionRatio);
      if (visible.length && visible[0]) {
        activeId.value = visible[0].target.id;
      }
    },
    {
      root,
      rootMargin: '-20% 0px -60% 0px',
      threshold: [0, 0.25, 0.5, 0.75, 1],
    },
  );

  targets.forEach(t => observer.current?.observe(t));
});

onUnmounted(() => {
  observer.current?.disconnect();
});
</script>

<template>
  <nav class="section-nav" role="navigation" aria-label="分区导航">
    <button
      v-for="s in sections"
      :key="s.id"
      class="nav-item"
      :class="{ active: activeId === s.id }"
      type="button"
      :aria-current="activeId === s.id ? 'true' : undefined"
      @click="scrollTo(s.id)"
    >
      <span class="nav-label">{{ s.label }}</span>
      <span class="nav-mark" aria-hidden="true" />
    </button>
  </nav>
</template>

