<script setup lang="ts">
import { computed, inject, ref, watch, type Ref } from 'vue';
import ChamferPanel from '../components/ChamferPanel.vue';
import StatusBadge from '../components/StatusBadge.vue';
import { useDataStore } from '../store';

type ViewMode = 'compact' | 'detail';

interface PartyMember {
  key: string;
  displayName: string;
  transformed: boolean;
  thought: string;
  emotions: { name: string; level: string; tone: string }[];
  isMagicalGirl: boolean;
  magicalGirlKey: string | null;
  hasUnresolvedKnots: boolean;
}

const store = useDataStore();

const PREF_KEY = 'msp_v5:party_view';
function getView(): ViewMode {
  try {
    const v = localStorage.getItem(PREF_KEY);
    return v === 'detail' ? 'detail' : 'compact';
  } catch {
    return 'compact';
  }
}
function setView(v: ViewMode) {
  try {
    localStorage.setItem(PREF_KEY, v);
  } catch {
    /* noop */
  }
}

const viewMode = ref<ViewMode>(getView());
const expanded = ref(new Set<string>());

const jumpToGirl = inject<(key: string) => void>('jumpToGirl', () => {});

const EMOTION_ORDER = ['极端', '强烈', '普通', '些许', '微弱'];

function emotionTone(level: string): string {
  switch (level) {
    case '微弱':
      return 'faint';
    case '些许':
      return 'light';
    case '普通':
      return 'normal-emo';
    case '强烈':
      return 'strong';
    case '极端':
      return 'extreme';
    default:
      return 'faint';
  }
}

function resolveMagicalGirl(
  name: string,
  girls: Record<string, Record<string, unknown>>,
): string | null {
  if (!name) return null;
  const n = name.trim();
  if (girls[n]) return n;
  for (const [key, g] of Object.entries(girls)) {
    if ((g.真名 as string)?.trim() === n || (g.魔法名 as string)?.trim() === n) return key;
  }
  return null;
}

const members = computed<PartyMember[]>(() => {
  const girls = ((store.data as Record<string, unknown>).魔法少女 as Record<string, Record<string, unknown>>) ?? {};
  const present = ((store.data as Record<string, unknown>).在场角色 as Record<string, Record<string, unknown>>) ?? {};

  return Object.entries(present)
    .map(([key, char]) => {
      const displayName = ((char.名称 as string) || key).trim() || key;
      const mgKey = resolveMagicalGirl(displayName, girls);
      const mg = mgKey ? girls[mgKey] : null;
      const knots = (mg?.心结 as Record<string, { 是否解开: boolean }>) ?? {};
      const hasUnresolved = Object.values(knots).some(k => !k?.是否解开);

      const emotions = Object.entries((char.感情 as Record<string, string>) ?? {})
        .map(([name, level]) => ({
          name,
          level,
          tone: emotionTone(level),
        }))
        .sort((a, b) => {
          const ai = EMOTION_ORDER.indexOf(a.level);
          const bi = EMOTION_ORDER.indexOf(b.level);
          return (ai === -1 ? 99 : ai) - (bi === -1 ? 99 : bi);
        });

      return {
        key,
        displayName,
        transformed: char.是否变身 === true,
        thought: (char.心声 as string) || '……',
        emotions,
        isMagicalGirl: mgKey !== null,
        magicalGirlKey: mgKey,
        hasUnresolvedKnots: hasUnresolved,
      };
    })
    .sort((a, b) => a.displayName.localeCompare(b.displayName, 'zh-Hans-CN'));
});

function toggleExpand(key: string) {
  if (expanded.value.has(key)) expanded.value.delete(key);
  else expanded.value.add(key);
}

function setMode(m: ViewMode) {
  viewMode.value = m;
  setView(m);
}

watch(
  () => members.value.map(m => m.key),
  keys => {
    const s = new Set(keys);
    expanded.value.forEach(k => {
      if (!s.has(k)) expanded.value.delete(k);
    });
  },
);
</script>

<template>
  <div class="party">
    <!-- Toolbar -->
    <div v-if="members.length" class="toolbar">
      <span class="count mono">{{ members.length }} 名在场</span>
      <div class="view-toggle" role="group" aria-label="视图模式">
        <button
          class="vt-btn"
          :class="{ active: viewMode === 'compact' }"
          type="button"
          title="紧凑视图"
          aria-label="紧凑视图"
          @click="setMode('compact')"
        >
          <svg viewBox="0 0 24 24" aria-hidden="true">
            <rect x="3" y="4" width="18" height="4" rx="0.5" fill="currentColor" />
            <rect x="3" y="10" width="18" height="4" rx="0.5" fill="currentColor" opacity="0.6" />
            <rect x="3" y="16" width="18" height="4" rx="0.5" fill="currentColor" opacity="0.3" />
          </svg>
        </button>
        <button
          class="vt-btn"
          :class="{ active: viewMode === 'detail' }"
          type="button"
          title="详细视图"
          aria-label="详细视图"
          @click="setMode('detail')"
        >
          <svg viewBox="0 0 24 24" aria-hidden="true">
            <rect x="3" y="3" width="8" height="8" rx="0.5" fill="currentColor" opacity="0.8" />
            <rect x="13" y="3" width="8" height="8" rx="0.5" fill="currentColor" opacity="0.5" />
            <rect x="3" y="13" width="8" height="8" rx="0.5" fill="currentColor" opacity="0.5" />
            <rect x="13" y="13" width="8" height="8" rx="0.5" fill="currentColor" opacity="0.8" />
          </svg>
        </button>
      </div>
    </div>

    <!-- Compact view -->
    <div v-if="members.length && viewMode === 'compact'" class="compact-list">
      <ChamferPanel
        v-for="m in members"
        :key="m.key"
        density="compact"
        :variant="m.isMagicalGirl ? 'primary' : 'default'"
        class="compact-card"
        :class="{ expanded: expanded.has(m.key) }"
        as="article"
      >
        <div class="compact-head" @click="toggleExpand(m.key)">
          <div class="compact-left">
            <span class="member-name">{{ m.displayName }}</span>
            <StatusBadge v-if="m.isMagicalGirl" tone="accent" size="xs">MG</StatusBadge>
            <span v-if="m.hasUnresolvedKnots" class="knot-pip" title="存在未解决心结" />
          </div>
          <div class="compact-right">
            <StatusBadge :tone="m.transformed ? 'mako' : 'default'" size="xs" dashed={!m.transformed}>
              {{ m.transformed ? '变身' : '常态' }}
            </StatusBadge>
            <div class="emo-mini">
              <template v-if="m.emotions.length">
                <StatusBadge
                  v-for="e in m.emotions.slice(0, 3)"
                  :key="e.name"
                  :tone="(e.tone as any)"
                  size="xs"
                >
                  {{ e.name }}
                </StatusBadge>
              </template>
              <span v-else class="no-emo">无感情</span>
            </div>
            <svg
              class="expand-ico"
              viewBox="0 0 24 24"
              :class="{ rotated: expanded.has(m.key) }"
              aria-hidden="true"
            >
              <path d="M6 9l6 6 6-6" stroke="currentColor" stroke-width="2" fill="none" stroke-linecap="round" />
            </svg>
          </div>
        </div>

        <Transition name="expand">
          <div v-if="expanded.has(m.key)" class="compact-detail">
            <div class="detail-row">
              <span class="detail-label">心声</span>
              <span class="detail-text">{{ m.thought }}</span>
            </div>
            <div v-if="m.emotions.length" class="detail-row">
              <span class="detail-label">感情</span>
              <div class="emo-tags">
                <StatusBadge
                  v-for="e in m.emotions"
                  :key="e.name"
                  :tone="(e.tone as any)"
                  size="xs"
                >
                  <strong>{{ e.name }}</strong>
                  <span class="emo-lvl">{{ e.level }}</span>
                </StatusBadge>
              </div>
            </div>
            <div v-if="m.isMagicalGirl && m.magicalGirlKey" class="detail-row">
              <span class="detail-label">档案</span>
              <button class="jump-btn" type="button" @click="jumpToGirl(m.magicalGirlKey)">
                查看魔法少女详情 →
              </button>
            </div>
          </div>
        </Transition>
      </ChamferPanel>
    </div>

    <!-- Detail view -->
    <div v-else-if="members.length && viewMode === 'detail'" class="detail-grid">
      <ChamferPanel
        v-for="m in members"
        :key="m.key"
        :variant="m.isMagicalGirl ? 'primary' : 'default'"
        :brackets="m.isMagicalGirl"
        class="detail-card"
        as="article"
      >
        <div class="card-head">
          <div class="card-name-block">
            <h3 class="card-name">
              {{ m.displayName }}
              <span v-if="m.hasUnresolvedKnots" class="knot-pip" title="存在未解决心结" />
            </h3>
            <div class="card-badges">
              <StatusBadge v-if="m.isMagicalGirl" tone="accent" size="xs">魔法少女</StatusBadge>
              <StatusBadge :tone="m.transformed ? 'mako' : 'default'" size="xs" dashed={!m.transformed}>
                {{ m.transformed ? '已变身' : '未变身' }}
              </StatusBadge>
            </div>
          </div>
        </div>

        <div class="thought-box">
          <div class="label">心声</div>
          <div class="thought-text">{{ m.thought }}</div>
        </div>

        <div class="emo-tags">
          <template v-if="m.emotions.length">
            <StatusBadge
              v-for="e in m.emotions"
              :key="e.name"
              :tone="(e.tone as any)"
              size="sm"
            >
              <strong>{{ e.name }}</strong>
              <span class="emo-lvl">{{ e.level }}</span>
            </StatusBadge>
          </template>
          <span v-else class="no-emo">暂无感情</span>
        </div>

        <div v-if="m.isMagicalGirl && m.magicalGirlKey" class="card-foot">
          <button class="jump-btn" type="button" @click="jumpToGirl(m.magicalGirlKey)">
            <svg viewBox="0 0 24 24" aria-hidden="true">
              <path d="M13 7l-5 5 5 5" stroke="currentColor" stroke-width="2" fill="none" stroke-linecap="round" />
            </svg>
            档案
          </button>
        </div>
      </ChamferPanel>
    </div>

    <!-- Empty -->
    <div v-else class="empty">
      <div class="empty-icon" aria-hidden="true">◇</div>
      <div class="empty-text">当前没有在场角色</div>
    </div>
  </div>
</template>

