<script setup lang="ts">
import { computed, provide, ref } from 'vue';
import ChamferPanel from './components/ChamferPanel.vue';
import Clock from './components/Clock.vue';
import SectionNav from './components/SectionNav.vue';
import ThemeToggle from './components/ThemeToggle.vue';
import PartySection from './pages/PartySection.vue';
import PlayerSection from './pages/PlayerSection.vue';
import ArchiveSection from './pages/ArchiveSection.vue';
import { useDataStore } from './store';

const store = useDataStore();

const SECTIONS = [
  { id: 'party', label: '在场' },
  { id: 'player', label: '渡鸦' },
  { id: 'archive', label: '档案' },
] as const;

// ── 跨分区跳转 (从在场角色跳到档案) ──
const selectGirlRef = ref<string | null>(null);

function jumpToGirl(key: string) {
  selectGirlRef.value = key;
  // 滚动到档案区
  requestAnimationFrame(() => {
    document.getElementById('archive')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    // 信号在 200ms 后清理, 让 ArchiveSection 有时间响应
    setTimeout(() => {
      selectGirlRef.value = null;
    }, 300);
  });
}

provide('jumpToGirl', jumpToGirl);
provide('selectGirlEvent', selectGirlRef);

const locationText = computed(() => {
  const loc = (store.data as Record<string, unknown>).地点 as
    | { 城市?: string; 地区?: string; 地址?: string }
    | undefined;
  return [loc?.城市?.trim() || '新都', loc?.地区?.trim() || '未知地区', loc?.地址?.trim() || '未知地点']
    .filter(Boolean)
    .join(' · ');
});
</script>

<template>
  <div class="shell scanlines">
    <!-- Sticky Header -->
    <header class="header">
      <ChamferPanel variant="primary" density="compact" chamfer="none" class="header-inner">
        <div class="header-row">
          <div class="loc-block">
            <span class="loc-icon" aria-hidden="true">◆</span>
            <span class="loc-eyebrow">LOC</span>
            <span class="loc-text">{{ locationText }}</span>
          </div>
          <div class="header-tools">
            <Clock />
            <ThemeToggle />
          </div>
        </div>
        <SectionNav :sections="[...SECTIONS]" class="nav-row" />
      </ChamferPanel>
    </header>

    <!-- Main Content -->
    <main class="main">
      <section id="party" class="section-block" aria-labelledby="party-head">
        <div class="section-head">
          <h2 id="party-head" class="section-title">
            <span class="section-index mono">01</span>
            <span class="section-name">在场角色</span>
            <span class="section-line" />
          </h2>
        </div>
        <PartySection />
      </section>

      <section id="player" class="section-block" aria-labelledby="player-head">
        <div class="section-head">
          <h2 id="player-head" class="section-title">
            <span class="section-index mono">02</span>
            <span class="section-name">渡鸦</span>
            <span class="section-line" />
          </h2>
        </div>
        <PlayerSection />
      </section>

      <section id="archive" class="section-block" aria-labelledby="archive-head">
        <div class="section-head">
          <h2 id="archive-head" class="section-title">
            <span class="section-index mono">03</span>
            <span class="section-name">魔法少女档案</span>
            <span class="section-line" />
          </h2>
        </div>
        <ArchiveSection />
      </section>
    </main>
  </div>
</template>

