<script setup lang="ts">
import { computed, onMounted, onUnmounted, ref } from 'vue';

const props = withDefaults(
  defineProps<{
    dayStart?: number;
    dayEnd?: number;
  }>(),
  {
    dayStart: 6,
    dayEnd: 18,
  },
);

const now = ref(new Date());
let timer: number | null = null;

onMounted(() => {
  timer = window.setInterval(() => {
    now.value = new Date();
  }, 30_000);
});
onUnmounted(() => {
  if (timer !== null) window.clearInterval(timer);
});

const hh = computed(() => String(now.value.getHours()).padStart(2, '0'));
const mm = computed(() => String(now.value.getMinutes()).padStart(2, '0'));

const isDay = computed(() => {
  const h = now.value.getHours();
  return h >= props.dayStart && h < props.dayEnd;
});
</script>

<template>
  <span class="clock mono" :class="isDay ? 'is-day' : 'is-night'" :title="isDay ? '日间时段' : '夜间时段'">
    <svg class="ico" viewBox="0 0 24 24" aria-hidden="true">
      <template v-if="isDay">
        <circle cx="12" cy="12" r="3.5" fill="currentColor" />
        <path
          d="M12 3v2M12 19v2M3 12h2M19 12h2M5.6 5.6l1.4 1.4M17 17l1.4 1.4M5.6 18.4L7 17M17 7l1.4-1.4"
          stroke="currentColor"
          stroke-width="1.6"
          stroke-linecap="round"
          fill="none"
        />
      </template>
      <template v-else>
        <path d="M20 12.5A8 8 0 1 1 11.5 4a6.5 6.5 0 0 0 8.5 8.5z" fill="currentColor" />
      </template>
    </svg>
    <span class="time">{{ hh }}:{{ mm }}</span>
  </span>
</template>

