<script setup lang="ts">
import { computed } from 'vue';

type Stage = 'surge' | 'high' | 'steady' | 'low' | 'empty';

const props = withDefaults(
  defineProps<{
    percent: number;
    current: number;
    max: number;
    stage: Stage;
    fallen: boolean;
    compact?: boolean;
    label?: string;
  }>(),
  {
    compact: false,
    label: '',
  },
);

let _uid = 0;
const uid = ++_uid;
const ID = (s: string) => `crystal-${uid}-${s}`;

// ViewBox
const VB_W = 100;
const VB_H = 132;
const TOP = 12; // top of table
const BOT = 124; // bottom culet
const FILL_SPAN = BOT - TOP;

// Gem outline (brilliant-cut front view)
const gemPath = 'M32,12 L68,12 L92,40 L92,60 L50,124 L8,60 L8,40 Z';

// Facet lines (interior, decorative)
const facetPaths = [
  'M32,12 L8,60', // left shoulder
  'M68,12 L92,60', // right shoulder
  'M32,12 L50,124', // left crown to culet
  'M68,12 L50,124', // right crown to culet
  'M8,40 L92,40', // girdle line
  'M50,12 L50,124', // center axis (subtle)
];

// Fallen crack lines
const crackPaths = [
  'M40,30 L48,50 L42,70 L52,95',
  'M60,28 L54,46 L62,68 L56,92',
  'M50,18 L46,38 L52,58 L48,80',
];

const fillY = computed(() => BOT - FILL_SPAN * (Math.max(0, Math.min(100, props.percent)) / 100));

const stageColors = computed(() => {
  const prefix = props.fallen ? 'crystal-fallen' : 'crystal-normal';
  const map: Record<Stage, { color: string; bright: string }> = {
    surge: {
      color: `var(--${prefix}-surge)`,
      bright: `var(--${prefix}-surge)`,
    },
    high: {
      color: `var(--${prefix}-high)`,
      bright: `var(--${prefix}-high)`,
    },
    steady: {
      color: `var(--${prefix}-steady)`,
      bright: `var(--${prefix}-steady)`,
    },
    low: {
      color: `var(--${prefix}-low)`,
      bright: `var(--${prefix}-low)`,
    },
    empty: {
      color: `var(--${prefix}-empty)`,
      bright: `var(--${prefix}-empty)`,
    },
  };
  return map[props.stage];
});

const sizePx = computed(() => (props.compact ? 38 : 130));
const aspect = VB_H / VB_W;

const stageClass = computed(() => `s-${props.stage}`);
const toneClass = computed(() => (props.fallen ? 'fallen' : 'normal'));
</script>

<template>
  <div
    class="crystal"
    :class="[stageClass, toneClass, { compact }]"
    :style="{ width: sizePx + 'px', height: sizePx * aspect + 'px' }"
  >
    <svg
      :viewBox="`0 0 ${VB_W} ${VB_H}`"
      :width="sizePx"
      :height="sizePx * aspect"
      xmlns="http://www.w3.org/2000/svg"
      overflow="visible"
    >
      <defs>
        <linearGradient :id="ID('fill')" x1="0" y1="1" x2="0" y2="0">
          <stop offset="0%" :stop-color="stageColors.color" stop-opacity="0.85" />
          <stop offset="60%" :stop-color="stageColors.bright" stop-opacity="0.95" />
          <stop offset="100%" :stop-color="stageColors.bright" stop-opacity="1" />
        </linearGradient>

        <linearGradient :id="ID('glaze')" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stop-color="rgba(255,255,255,0.35)" />
          <stop offset="40%" stop-color="rgba(255,255,255,0.08)" />
          <stop offset="100%" stop-color="rgba(255,255,255,0)" />
        </linearGradient>

        <clipPath :id="ID('clip')">
          <path :d="gemPath" />
        </clipPath>

        <filter :id="ID('glow')" x="-50%" y="-50%" width="200%" height="200%">
          <feGaussianBlur stdDeviation="2.2" />
        </filter>
      </defs>

      <!-- Outer halo (glow behind gem) -->
      <path
        v-if="!compact"
        :d="gemPath"
        class="halo"
        :filter="`url(#${ID('glow')})`"
        :fill="stageColors.bright"
      />

      <!-- Gem outline (frame) -->
      <path :d="gemPath" class="frame" />

      <!-- Fill (clipped to gem shape) -->
      <g :clip-path="`url(#${ID('clip')})`">
        <rect
          class="fill-rect"
          :x="0"
          :y="fillY"
          :width="VB_W"
          :height="VB_H - fillY"
          :fill="`url(#${ID('fill')})`"
        />
        <!-- Specular highlight at fill surface -->
        <rect
          v-if="percent > 0 && percent < 100"
          class="surface-line"
          :x="0"
          :y="fillY - 0.6"
          :width="VB_W"
          :height="1.4"
        />
        <!-- Top glaze (always present, like glass) -->
        <rect :x="0" :y="0" :width="VB_W" :height="VB_H" :fill="`url(#${ID('glaze')})`" />
      </g>

      <!-- Facet lines -->
      <g v-if="!compact" class="facets" :clip-path="`url(#${ID('clip')})`">
        <path v-for="(d, i) in facetPaths" :key="i" :d="d" />
      </g>

      <!-- Fallen cracks (overlay) -->
      <g v-if="fallen && !compact" class="cracks" :clip-path="`url(#${ID('clip')})`">
        <path v-for="(d, i) in crackPaths" :key="`c${i}`" :d="d" />
      </g>

      <!-- Outline overlay (re-draw on top for crisp edge) -->
      <path :d="gemPath" class="outline-top" />

      <!-- Center label -->
      <template v-if="compact">
        <text
          :x="VB_W / 2"
          :y="VB_H / 2 + 1"
          class="compact-num"
          text-anchor="middle"
          dominant-baseline="central"
        >
          {{ percent }}
        </text>
      </template>
      <template v-else>
        <text
          :x="VB_W / 2"
          :y="VB_H / 2 - 6"
          class="big-num"
          text-anchor="middle"
          dominant-baseline="central"
        >
          {{ percent }}<tspan class="pct">%</tspan>
        </text>
        <text
          :x="VB_W / 2"
          :y="VB_H / 2 + 14"
          class="sub-num"
          text-anchor="middle"
          dominant-baseline="central"
        >
          {{ current }} / {{ max }}
        </text>
        <text
          v-if="label"
          :x="VB_W / 2"
          :y="VB_H - 6"
          class="stage-label"
          text-anchor="middle"
          dominant-baseline="central"
        >
          {{ label }}
        </text>
      </template>
    </svg>
  </div>
</template>

<style scoped>
