<script setup lang="ts">
import { computed } from 'vue';

interface Attr {
  grade: string;
  note: string;
}

const props = defineProps<{
  data: Record<string, Attr>;
}>();

const ATTR_ORDER = [
  '基准值',
  '发动值',
  '集束性',
  '扩散性',
  '操纵性',
  '付属性',
  '维持性',
  '干涉性',
] as const;

const VB = 260;
const CX = VB / 2;
const CY = VB / 2;
const R_MAX = 86;
const RING_COUNT = 4;

// Grade → 0..1 value
const GRADE_VALUE: Record<string, number> = {
  E: 0.15,
  'E-': 0.1,
  'E+': 0.22,
  D: 0.3,
  'D-': 0.25,
  'D+': 0.38,
  C: 0.45,
  'C-': 0.4,
  'C+': 0.52,
  B: 0.6,
  'B-': 0.55,
  'B+': 0.66,
  A: 0.74,
  'A-': 0.7,
  'A+': 0.8,
  AA: 0.86,
  'AA-': 0.82,
  'AA+': 0.9,
  AAA: 0.94,
  'AAA-': 0.92,
  'AAA+': 0.97,
  EX: 1,
  'EX+': 1,
};

function gradeToValue(grade: string): number {
  const g = grade.trim().toUpperCase();
  if (!g || g === '—') return 0.1;
  if (GRADE_VALUE[g] !== undefined) return GRADE_VALUE[g];

  // range like "B~A" or "C/D"
  const range = g.match(/^([A-Z+-]+)[~/]([A-Z+-]+)$/);
  if (range) {
    const a = GRADE_VALUE[range[1]] ?? 0.3;
    const b = GRADE_VALUE[range[2]] ?? 0.7;
    return (a + b) / 2;
  }

  // ends with ++ → nudge toward next tier
  if (g.endsWith('++')) {
    const base = GRADE_VALUE[g.slice(0, -2)] ?? 0.4;
    return Math.min(1, base + 0.08);
  }

  // last token fallback
  const tokens = g.split(/[\s/~]/);
  for (const t of tokens) {
    if (GRADE_VALUE[t] !== undefined) return GRADE_VALUE[t];
  }
  return 0.2;
}

const GRADE_COLOR: Record<string, string> = {
  E: 'var(--grade-e)',
  D: 'var(--grade-d)',
  C: 'var(--grade-c)',
  B: 'var(--grade-b)',
  A: 'var(--grade-a)',
  AA: 'var(--grade-aa)',
  AAA: 'var(--grade-aaa)',
  EX: 'var(--grade-ex)',
};

function gradeColor(grade: string): string {
  const g = grade.trim().toUpperCase();
  if (!g || g === '—') return 'var(--grade-e)';
  // take leading tier letter(s)
  const m = g.match(/^(AAA|AA|A|B|C|D|E|EX)/);
  if (m && GRADE_COLOR[m[1]]) return GRADE_COLOR[m[1]];
  return 'var(--grade-e)';
}

// Axis geometry
type Anchor = 'middle' | 'start' | 'end';

interface AxisInfo {
  name: string;
  angle: number;
  value: number;
  grade: string;
  note: string;
  vx: number;
  vy: number;
  lx: number;
  ly: number;
  anchor: Anchor;
}

const axes = computed<AxisInfo[]>(() =>
  ATTR_ORDER.map((name, i) => {
    const angle = (-90 + i * 45) * (Math.PI / 180);
    const attr = props.data[name];
    const value = attr ? gradeToValue(attr.grade) : 0;
    const vx = CX + R_MAX * value * Math.cos(angle);
    const vy = CY + R_MAX * value * Math.sin(angle);
    const lx = CX + (R_MAX + 20) * Math.cos(angle);
    const ly = CY + (R_MAX + 20) * Math.sin(angle);
    const cosA = Math.cos(angle);
    const anchor: Anchor = Math.abs(cosA) < 0.1 ? 'middle' : cosA > 0 ? 'start' : 'end';
    return {
      name,
      angle,
      value,
      grade: attr?.grade ?? '—',
      note: attr?.note ?? '',
      vx,
      vy,
      lx,
      ly,
      anchor,
    };
  }),
);

// Filled polygon points
const polygonPoints = computed(() => axes.value.map(a => `${a.vx},${a.vy}`).join(' '));

// Grid rings (octagons)
const rings = computed(() => {
  const out: string[] = [];
  for (let r = 1; r <= RING_COUNT; r++) {
    const radius = (R_MAX * r) / RING_COUNT;
    const pts = ATTR_ORDER.map((_, i) => {
      const angle = (-90 + i * 45) * (Math.PI / 180);
      return `${CX + radius * Math.cos(angle)},${CY + radius * Math.sin(angle)}`;
    });
    out.push(pts.join(' '));
  }
  return out;
});

// Axis lines from center to outer
const axisLines = computed(() =>
  ATTR_ORDER.map((_, i) => {
    const angle = (-90 + i * 45) * (Math.PI / 180);
    return {
      x2: CX + R_MAX * Math.cos(angle),
      y2: CY + R_MAX * Math.sin(angle),
    };
  }),
);

const uid = Math.random().toString(36).slice(2, 8);
</script>

<template>
  <div class="radar">
    <svg :viewBox="`0 0 ${VB} ${VB}`" :width="220" :height="220" xmlns="http://www.w3.org/2000/svg">
      <defs>
        <radialGradient :id="`rg-${uid}`" cx="50%" cy="50%" r="50%">
          <stop offset="0%" stop-color="var(--accent)" stop-opacity="0.5" />
          <stop offset="100%" stop-color="var(--accent)" stop-opacity="0.18" />
        </radialGradient>
        <filter :id="`rg-glow-${uid}`" x="-30%" y="-30%" width="160%" height="160%">
          <feGaussianBlur stdDeviation="1.4" />
        </filter>
      </defs>

      <!-- Background rings -->
      <polygon
        v-for="(pts, i) in rings"
        :key="`r${i}`"
        :points="pts"
        class="ring"
        :class="{ outer: i === rings.length - 1 }"
      />

      <!-- Axis lines -->
      <line
        v-for="(l, i) in axisLines"
        :key="`a${i}`"
        :x1="CX"
        :y1="CY"
        :x2="l.x2"
        :y2="l.y2"
        class="axis"
      />

      <!-- Filled polygon -->
      <polygon
        :points="polygonPoints"
        :fill="`url(#rg-${uid})`"
        class="value-area"
        :filter="`url(#rg-glow-${uid})`"
      />

      <!-- Polygon outline -->
      <polygon :points="polygonPoints" class="value-line" />

      <!-- Vertex dots -->
      <circle
        v-for="(a, i) in axes"
        :key="`v${i}`"
        :cx="a.vx"
        :cy="a.vy"
        :r="2.4"
        :fill="gradeColor(a.grade)"
      />

      <!-- Attribute labels with grade -->
      <g v-for="(a, i) in axes" :key="`l${i}`" :transform="`translate(${a.lx}, ${a.ly})`">
        <text
          y="-2"
          :text-anchor="a.anchor"
          class="label-name"
        >
          {{ a.name }}
        </text>
        <text
          y="12"
          :text-anchor="a.anchor"
          class="label-grade"
          :fill="gradeColor(a.grade)"
        >
          {{ a.grade }}
        </text>
      </g>
    </svg>

    <!-- Notes (optional, below chart) -->
    <details v-if="axes.some(a => a.note)" class="notes">
      <summary>能力注解</summary>
      <ul>
        <li v-for="(a, i) in axes.filter(a => a.note)" :key="`n${i}`">
          <span class="note-name" :style="{ color: gradeColor(a.grade) }">{{ a.name }}</span>
          <span class="note-grade">{{ a.grade }}</span>
          <span class="note-text">{{ a.note }}</span>
        </li>
      </ul>
    </details>
  </div>
</template>

